// ===== JSON MASTERY =====

const articles = [
  { id: 1706000001000, title: 'HTML Dasar',    content: 'Belajar tag semantik...' },
  { id: 1706000002000, title: 'CSS Flexbox',   content: 'Layout responsif...' },
  { id: 1706000003000, title: 'JavaScript DOM', content: 'Manipulasi elemen...' }
];

// STRINGIFY: Array/Object → String (untuk disimpan)
const jsonString = JSON.stringify(articles);
console.log(typeof jsonString); // 'string'
console.log(jsonString);
// Output: '[{"id":1706000001000,"title":"HTML Dasar",...}]'

// PARSE: String → Array/Object (untuk digunakan)
const parsedArticles = JSON.parse(jsonString);
console.log(typeof parsedArticles); // 'object' (array)
console.log(parsedArticles[0].title); // 'HTML Dasar'

// ⚠️ Siklus yang akan digunakan di LocalStorage:
// Simpan : localStorage.setItem('articles', JSON.stringify(articles))
// Ambil  : JSON.parse(localStorage.getItem('articles'))

// ===== .filter() — Hapus berdasarkan ID =====
// Mengembalikan array baru tanpa item yang id-nya cocok
function deleteArticle(id) {
  articles = articles.filter(article => article.id !== id);
  // Semua artikel KECUALI yang id-nya sama dengan parameter
}

// ===== .find() — Cari satu item berdasarkan ID =====
// Mengembalikan item pertama yang cocok, atau undefined
function setupEdit(id) {
  const article = articles.find(a => a.id === id);
  if (article) {
    editTitle.value   = article.title;
    editContent.value = article.content;
    editId.value      = article.id; // Simpan ID di hidden input
    openModal();
  }
}

// ===== .map() — Transformasi seluruh array =====
// Mengembalikan array baru dengan setiap item ditransformasi
const titleList = articles.map(a => a.title);
// ['HTML Dasar', 'CSS Flexbox', 'JavaScript DOM']

const tableRows = articles.map((a, i) =>
  `<tr><td>${i+1}</td><td>${a.title}</td></tr>`
).join('');
// Alternatif renderTable() yang lebih fungsional

// ===== .findIndex() — Cari posisi untuk Update =====
function updateArticle(id, newTitle, newContent) {
  const index = articles.findIndex(a => a.id === id);
  if (index !== -1) {
    articles[index].title   = newTitle;
    articles[index].content = newContent;
    renderTable();
  }
}
